output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?club(COUNT(?season) AS ?count) WHERE {
  VALUES ?club {
    wd:Q249679 wd:Q3044572
  }
  VALUES ?league {
    wd:Q447247 wd:Q17733
  }
  ?season wdt:P179 ?league .
  ?season wdt:P3967 ?finalEvent .
  ?finalEvent wdt:P1344 ?club .
}
GROUP BY ?club
ORDER BY DESC(?count)
LIMIT 1

